        v[b].second -= v[a].second;

        a++;

      } else {

        v[a].second -= v[b].second;

        b--;

      }

    }

    ll line = v[a].first;

    ll val = 0;

    REP(i, N) if (s >> i & 1) val += P[i] * abs(X[i] - line);

    chmin(res, val);

  }

