    vector<pair<ll, ll>> v;

    REP(i, N) if (s >> i & 1) v.push_back({Y[i], P[i]});

    sort(ALL(v));

    int a = 0, b = v.size() - 1;

    while (a < b) {

      if (v[a].second <= v[b].second) {

        v[b].second -= v[a].second;

        a++;

      } else {

        v[a].second -= v[b].second;

        b--;

      }

    }

    ll line = v[a].first;

    ll val = 0;

    REP(i, N) if (s >> i & 1) val += P[i] * abs(Y[i] - line);

    chmin(res, val);

  }



  return memo[s] = res;

}





