  CLR(dp, -1);

  CLR(memo, -1);



  N = nextLong();

  REP(i, N) {

    X[i] = nextLong();

    Y[i] = nextLong();

    P[i] = nextLong();

  }



  REP(s, 1<<N) REP(k, N+1) dp[s][k] = INF;



  REP(s, 1<<N) {

